diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..f0d602bfcad2 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3857,6 +3857,29 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+  // select(C2, select(C1, A, B), select(C1, B, A)) -> select(C1 ^ C2, B, A)
+  // select(C2, select(C1, B, A), select(C1, A, B)) -> select(C1 ^ C2, B, A)
+  if (SelectInst *TrueSI2 = dyn_cast<SelectInst>(TrueVal)) {
+    if (SelectInst *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+      if (TrueSI2->hasOneUse() && FalseSI->hasOneUse() &&
+          TrueSI2->getCondition() == FalseSI->getCondition()) {
+        Value *InnerCond = TrueSI2->getCondition();
+        if (InnerCond->getType() == CondVal->getType()) {
+          Value *A = TrueSI2->getTrueValue();
+          Value *B = TrueSI2->getFalseValue();
+          // Check if FalseSI has swapped operands
+          if (FalseSI->getTrueValue() == B && FalseSI->getFalseValue() == A) {
+            Value *Xor = Builder.CreateXor(InnerCond, CondVal);
+            replaceOperand(SI, 0, Xor);
+            replaceOperand(SI, 1, B);
+            replaceOperand(SI, 2, A);
+            return &SI;
+          }
+        }
+      }
+    }
+  }
+
   // Try to simplify a binop sandwiched between 2 selects with the same
   // condition. This is not valid for div/rem because the select might be
   // preventing a division-by-zero.

log.source_program:
define i32 @select_of_symmetric_selects(i32 %a, i32 %b, i1 %c1, i1 %c2) {
  %sel1 = select i1 %c1, i32 %a, i32 %b
  %sel2 = select i1 %c1, i32 %b, i32 %a
  %ret = select i1 %c2, i32 %sel1, i32 %sel2
  ret i32 %ret
}

log.expect_optimized_program:
define i32 @select_of_symmetric_selects(i32 %a, i32 %b, i1 %c1, i1 %c2) {
  %1 = xor i1 %c1, %c2
  %ret = select i1 %1, i32 %b, i32 %a
  ret i32 %ret
}

